106→    /**
107→     * Find all of the {@link StreamsMetadata}s for a given storeName
108→     *
109→     * @param storeName the storeName to find metadata for
110→     * @return A collection of {@link StreamsMetadata} that have the provided storeName
111→     */
112→    public synchronized Collection<StreamsMetadata> allMetadataForStore(final String storeName) {
113→        Objects.requireNonNull(storeName, "storeName cannot be null");
114→        if (topologyMetadata.hasNamedTopologies()) {
115→            throw new IllegalArgumentException("Cannot invoke the allMetadataForStore(storeName) method when"
116→                                                   + "using named topologies, please use the overload that accepts"
117→                                                   + "a topologyName parameter to identify the correct store");
118→        }
119→
120→        if (!isInitialized()) {
121→            return Collections.emptyList();
122→        }
123→
124→        if (globalStores.contains(storeName)) {
125→            return allMetadata;
126→        }
127→
128→        final Collection<String> sourceTopics = topologyMetadata.sourceTopicsForStore(storeName, null);
129→        if (sourceTopics.isEmpty()) {
130→            return Collections.emptyList();
131→        }
132→
133→        final ArrayList<StreamsMetadata> results = new ArrayList<>();
134→        for (final StreamsMetadata metadata : allMetadata) {
135→            if (metadata.stateStoreNames().contains(storeName) || metadata.standbyStateStoreNames().contains(storeName)) {
136→                results.add(metadata);
137→            }
138→        }
139→        return results;
140→    }
