147→     * @return A collection of {@link StreamsMetadata} that have the provided storeName
148→     */
149→    public synchronized Collection<StreamsMetadata> allMetadataForStore(final String storeName, final String topologyName) {
150→        Objects.requireNonNull(storeName, "storeName cannot be null");
151→        Objects.requireNonNull(topologyName, "topologyName cannot be null");
152→
153→        if (!isInitialized()) {
154→            return Collections.emptyList();
155→        }
156→
157→        final Collection<String> sourceTopics = topologyMetadata.sourceTopicsForStore(storeName, topologyName);
158→        if (sourceTopics.isEmpty()) {
159→            return Collections.emptyList();
160→        }
161→
162→        final ArrayList<StreamsMetadata> results = new ArrayList<>();
163→        for (final StreamsMetadata metadata : allMetadata) {
164→            final String metadataTopologyName = ((StreamsMetadataImpl) metadata).topologyName();
165→            if (metadataTopologyName != null && metadataTopologyName.equals(topologyName)
166→                && metadata.stateStoreNames().contains(storeName) || metadata.standbyStateStoreNames().contains(storeName)) {
167→                results.add(metadata);
168→            }
169→        }
170→        return results;
171→    }
