238→     * {@link StreamsMetadata} it would exist on.
239→     *
240→     * @param storeName   Name of the store
241→     * @param key         Key to use
242→     * @param partitioner partitioner to use to find correct partition for key
243→     * @param <K>         key type
244→     * @return The {@link KeyQueryMetadata} for the storeName and key or {@link KeyQueryMetadata#NOT_AVAILABLE}
245→     * if streams is (re-)initializing, or {@code null} if no matching metadata could be found.
246→     */
247→    public synchronized <K> KeyQueryMetadata keyQueryMetadataForKey(final String storeName,
248→                                                                    final K key,
249→                                                                    final StreamPartitioner<? super K, ?> partitioner) {
250→        Objects.requireNonNull(storeName, "storeName can't be null");
251→        Objects.requireNonNull(key, "key can't be null");
252→        Objects.requireNonNull(partitioner, "partitioner can't be null");
253→        if (topologyMetadata.hasNamedTopologies()) {
254→            throw new IllegalArgumentException("Cannot invoke the keyQueryMetadataForKey(storeName, key, partitioner)"
255→                                                   + "method when using named topologies, please use the overload that"
256→                                                   + "accepts a topologyName parameter to identify the correct store");
257→        }
258→
259→        if (!isInitialized()) {
260→            return KeyQueryMetadata.NOT_AVAILABLE;
261→        }
262→
263→        if (globalStores.contains(storeName)) {
264→            // global stores are on every node. if we don't have the host info
265→            // for this host then just pick the first metadata
266→            if (thisHost.equals(UNKNOWN_HOST)) {
267→                return new KeyQueryMetadata(allMetadata.get(0).hostInfo(), Collections.emptySet(), UNKNOWN_PARTITION);
268→            }
269→            return new KeyQueryMetadata(localMetadata.get().hostInfo(), Collections.emptySet(), UNKNOWN_PARTITION);
270→        }
271→
272→        final SourceTopicsInfo sourceTopicsInfo = getSourceTopicsInfo(storeName);
273→        if (sourceTopicsInfo == null) {
274→            return null;
275→        }
276→        return keyQueryMetadataForKey(storeName, key, partitioner, sourceTopicsInfo);
277→    }
