1255→    /*
1256→     * Takes a snapshot and counts the number of stream threads which are not in PENDING_SHUTDOWN or DEAD
1257→     *
1258→     * Note: iteration over SynchronizedList is not thread safe, so it must be manually synchronized. However, we may
1259→     * require other locks when looping threads, and it could cause deadlock. Hence, we create a copy to avoid holding
1260→     * threads lock when looping threads.
1261→     *
1262→     * @return number of alive stream threads
1263→     */
1264→    private int numLiveStreamThreads() {
1265→        final AtomicInteger numLiveThreads = new AtomicInteger(0);
1266→
1267→        synchronized (threads) {
1268→            processStreamThread(thread -> {
1269→                if (thread.state() == StreamThread.State.DEAD) {
1270→                    log.debug("Trimming thread {} from the threads list since it's state is {}", thread.getName(), StreamThread.State.DEAD);
1271→                    threads.remove(thread);
1272→                } else if (thread.state() == StreamThread.State.PENDING_SHUTDOWN) {
1273→                    log.debug("Skipping thread {} from num live threads computation since it's state is {}",
1274→                              thread.getName(), StreamThread.State.PENDING_SHUTDOWN);
1275→                } else {
1276→                    numLiveThreads.incrementAndGet();
1277→                }
1278→            });
1279→            return numLiveThreads.get();
1280→        }
1281→    }
